This Python function processes a 10 million row CSV file and takes 45 minutes. Profile it, identify the bottlenecks, and optimize it to under 1 minute. Show your profiling methodology and explain each optimization.

```python
import csv

def process_csv(filename):
    results = []
    with open(filename) as f:
        reader = csv.DictReader(f)
        for row in reader:
            name = row['name'].strip().lower()
            amount = float(row['amount'])
            date = row['date']
            category = categorize(name)
            if amount > 100:
                results.append({
                    'name': name,
                    'amount': amount,
                    'date': date,
                    'category': category,
                })

    # Group by category
    grouped = {}
    for item in results:
        cat = item['category']
        if cat not in grouped:
            grouped[cat] = []
        grouped[cat].append(item)

    # Sort each group by amount
    for cat in grouped:
        grouped[cat].sort(key=lambda x: x['amount'], reverse=True)

    return grouped

def categorize(name):
    categories = {
        'food': ['restaurant', 'grocery', 'cafe', 'pizza', 'sushi'],
        'transport': ['uber', 'lyft', 'gas', 'parking', 'toll'],
        'entertainment': ['netflix', 'spotify', 'cinema', 'game', 'book'],
        'utilities': ['electric', 'water', 'internet', 'phone', 'insurance'],
    }
    for category, keywords in categories.items():
        for keyword in keywords:
            if keyword in name:
                return category
    return 'other'
